     1→/**
     2→ * Link Library Store
     3→ *
     4→ * Manages links (bookmarks) with:
     5→ * - Import/Export (Netscape HTML format)
     6→ * - Collections for organization
     7→ * - AI-powered categorization
     8→ * - Favorites and archive features
     9→ *
    10→ * Persists to IndexedDB via createSyncedStorage.
    11→ */
    12→
    13→import { create } from 'zustand';
    14→import { persist, createJSONStorage } from 'zustand/middleware';
    15→import { createSyncedStorage } from '../lib/syncedStorage';
    16→import { useProjectContextStore } from './useProjectContextStore';
    17→
    18→// ============================================================================
    19→// Types
    20→// ============================================================================
    21→
    22→export interface Link {
    23→  id: string;
    24→  url: string;
    25→  title: string;
    26→  description?: string;
    27→  favicon?: string;
    28→  category?: string; // AI-suggested or manual
    29→  tags: string[];
    30→  projectIds: string[]; // Project context IDs for global filter system (empty = uncategorized)
    31→  isFavorite: boolean;
    32→  isArchived: boolean;
    33→  lastVisited?: Date;
    34→  visitCount: number;
    35→  createdAt: Date;
    36→  updatedAt: Date;
    37→}
    38→
    39→export interface LinkCollection {
    40→  id: string;
    41→  name: string;
    42→  icon?: string; // Emoji or custom
    43→  color?: string; // Accent color
    44→  linkIds: string[]; // Ordered list of link IDs
    45→  isExpanded: boolean;
    46→  sortOrder: number;
    47→  createdAt: Date;
    48→  updatedAt: Date;
    49→}
    50→
    51→export type ViewMode = 'grid' | 'list';
    52→export type SortField = 'title' | 'createdAt' | 'updatedAt' | 'visitCount';
    53→export type SortDirection = 'asc' | 'desc';
    54→
    55→interface LinkLibraryState {
    56→  // Data
    57→  links: Record<string, Link>;
    58→  collections: Record<string, LinkCollection>;
    59→
    60→  // UI State (not persisted)
    61→  viewMode: ViewMode;
    62→  sortField: SortField;
    63→  sortDirection: SortDirection;
    64→  searchQuery: string;
    65→  activeCollectionId: string | null; // null = all links
    66→  selectedLinkIds: Set<string>; // For bulk operations
    67→}
    68→
    69→interface LinkLibraryActions {
    70→  // Link CRUD
    71→  addLink: (data: Omit<Link, 'id' | 'createdAt' | 'updatedAt' | 'visitCount'>) => Link;
    72→  updateLink: (id: string, updates: Partial<Omit<Link, 'id' | 'createdAt'>>) => void;
    73→  deleteLink: (id: string) => void;
    74→  deleteLinks: (ids: string[]) => void;
    75→
    76→  // Link Operations
    77→  toggleFavorite: (id: string) => void;
    78→  toggleArchived: (id: string) => void;
    79→  incrementVisitCount: (id: string) => void;
    80→  setLinkCategory: (id: string, category: string) => void;
    81→  addTagsToLink: (id: string, tags: string[]) => void;
    82→  removeTagsFromLink: (id: string, tags: string[]) => void;
    83→
    84→  // Collection CRUD
    85→  addCollection: (data: Omit<LinkCollection, 'id' | 'createdAt' | 'updatedAt' | 'sortOrder'>) => LinkCollection;
    86→  updateCollection: (id: string, updates: Partial<Omit<LinkCollection, 'id' | 'createdAt'>>) => void;
    87→  deleteCollection: (id: string) => void;
    88→  reorderCollections: (orderedIds: string[]) => void;
    89→
    90→  // Collection Operations
    91→  addLinkToCollection: (linkId: string, collectionId: string) => void;
    92→  removeLinkFromCollection: (linkId: string, collectionId: string) => void;
    93→  moveLinkBetweenCollections: (linkId: string, fromCollectionId: string, toCollectionId: string) => void;
    94→  reorderLinksInCollection: (collectionId: string, orderedLinkIds: string[]) => void;
    95→
    96→  // Bulk Import
    97→  importLinks: (links: Omit<Link, 'id' | 'createdAt' | 'updatedAt' | 'visitCount'>[]) => Link[];
    98→
    99→  // UI State
   100→  setViewMode: (mode: ViewMode) => void;
   101→  setSortField: (field: SortField) => void;
   102→  setSortDirection: (direction: SortDirection) => void;
   103→  setSearchQuery: (query: string) => void;
   104→  setActiveCollection: (collectionId: string | null) => void;
   105→  toggleLinkSelection: (id: string) => void;
   106→  selectAllLinks: (ids: string[]) => void;
   107→  clearSelection: () => void;
   108→
   109→  // Queries
   110→  getLink: (id: string) => Link | undefined;
   111→  getAllLinks: () => Link[];
   112→  getFilteredLinks: () => Link[];
   113→  getLinksInCollection: (collectionId: string) => Link[];
   114→  getFavoriteLinks: () => Link[];
   115→  getArchivedLinks: () => Link[];
   116→  searchLinks: (query: string) => Link[];
   117→  getAllTags: () => string[];
   118→  getAllCategories: () => string[];
   119→}
   120→
   121→type LinkLibraryStore = LinkLibraryState & LinkLibraryActions;
   122→
   123→// ============================================================================
   124→// Utility Functions
   125→// ============================================================================
   126→
   127→const generateId = () => `link_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
   128→const generateCollectionId = () => `col_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
   129→
   130→// ============================================================================
   131→// Store Implementation
   132→// ============================================================================
   133→
   134→export const useLinkLibraryStore = create<LinkLibraryStore>()(
   135→  persist(
   136→    (set, get) => ({
   137→      // Initial State
   138→      links: {},
   139→      collections: {},
   140→      viewMode: 'grid',
   141→      sortField: 'createdAt',
   142→      sortDirection: 'desc',
   143→      searchQuery: '',
   144→      activeCollectionId: null,
   145→      selectedLinkIds: new Set(),
   146→
   147→      // ========================================================================
   148→      // Link CRUD
   149→      // ========================================================================
   150→
   151→      addLink: (data) => {
   152→        const id = generateId();
   153→        const now = new Date();
   154→        const link: Link = {
   155→          ...data,
   156→          id,
   157→          visitCount: 0,
   158→          createdAt: now,
   159→          updatedAt: now,
   160→        };
   161→
   162→        set((state) => ({
   163→          links: { ...state.links, [id]: link },
   164→        }));
   165→
   166→        return link;
   167→      },
   168→
   169→      updateLink: (id, updates) => {
   170→        set((state) => {
   171→          const existing = state.links[id];
   172→          if (!existing) return state;
   173→
   174→          return {
   175→            links: {
   176→              ...state.links,
   177→              [id]: {
   178→                ...existing,
   179→                ...updates,
   180→                updatedAt: new Date(),
   181→              },
   182→            },
   183→          };
   184→        });
   185→      },
   186→
   187→      deleteLink: (id) => {
   188→        set((state) => {
   189→          const { [id]: _, ...remainingLinks } = state.links;
   190→
   191→          // Remove from all collections
   192→          const updatedCollections = { ...state.collections };
   193→          Object.values(updatedCollections).forEach((collection) => {
   194→            collection.linkIds = collection.linkIds.filter((linkId) => linkId !== id);
   195→          });
   196→
   197→          // Remove from selection
   198→          const newSelection = new Set(state.selectedLinkIds);
   199→          newSelection.delete(id);
   200→
   201→          return {
   202→            links: remainingLinks,
   203→            collections: updatedCollections,
   204→            selectedLinkIds: newSelection,
   205→          };
   206→        });
   207→      },
   208→
   209→      deleteLinks: (ids) => {
   210→        set((state) => {
   211→          const idsSet = new Set(ids);
   212→          const remainingLinks: Record<string, Link> = {};
   213→
   214→          Object.entries(state.links).forEach(([id, link]) => {
   215→            if (!idsSet.has(id)) {
   216→              remainingLinks[id] = link;
   217→            }
   218→          });
   219→
   220→          // Remove from all collections
   221→          const updatedCollections = { ...state.collections };
   222→          Object.values(updatedCollections).forEach((collection) => {
   223→            collection.linkIds = collection.linkIds.filter((linkId) => !idsSet.has(linkId));
   224→          });
   225→
   226→          // Remove from selection
   227→          const newSelection = new Set(state.selectedLinkIds);
   228→          ids.forEach((id) => newSelection.delete(id));
   229→
   230→          return {
   231→            links: remainingLinks,
   232→            collections: updatedCollections,
   233→            selectedLinkIds: newSelection,
   234→          };
   235→        });
   236→      },
   237→
   238→      // ========================================================================
   239→      // Link Operations
   240→      // ========================================================================
   241→
   242→      toggleFavorite: (id) => {
   243→        set((state) => {
   244→          const link = state.links[id];
   245→          if (!link) return state;
   246→
   247→          return {
   248→            links: {
   249→              ...state.links,
   250→              [id]: {
   251→                ...link,
   252→                isFavorite: !link.isFavorite,
   253→                updatedAt: new Date(),
   254→              },
   255→            },
   256→          };
   257→        });
   258→      },
   259→
   260→      toggleArchived: (id) => {
   261→        set((state) => {
   262→          const link = state.links[id];
   263→          if (!link) return state;
   264→
   265→          return {
   266→            links: {
   267→              ...state.links,
   268→              [id]: {
   269→                ...link,
   270→                isArchived: !link.isArchived,
   271→                updatedAt: new Date(),
   272→              },
   273→            },
   274→          };
   275→        });
   276→      },
   277→
   278→      incrementVisitCount: (id) => {
   279→        set((state) => {
   280→          const link = state.links[id];
   281→          if (!link) return state;
   282→
   283→          return {
   284→            links: {
   285→              ...state.links,
   286→              [id]: {
   287→                ...link,
   288→                visitCount: link.visitCount + 1,
   289→                lastVisited: new Date(),
   290→                updatedAt: new Date(),
   291→              },
   292→            },
   293→          };
   294→        });
   295→      },
   296→
   297→      setLinkCategory: (id, category) => {
   298→        set((state) => {
   299→          const link = state.links[id];
   300→          if (!link) return state;
   301→
   302→          return {
   303→            links: {
   304→              ...state.links,
   305→              [id]: {
   306→                ...link,
   307→                category,
   308→                updatedAt: new Date(),
   309→              },
   310→            },
   311→          };
   312→        });
   313→      },
   314→
   315→      addTagsToLink: (id, tags) => {
   316→        set((state) => {
   317→          const link = state.links[id];
   318→          if (!link) return state;
   319→
   320→          const uniqueTags = [...new Set([...link.tags, ...tags])];
   321→
   322→          return {
   323→            links: {
   324→              ...state.links,
   325→              [id]: {
   326→                ...link,
   327→                tags: uniqueTags,
   328→                updatedAt: new Date(),
   329→              },
   330→            },
   331→          };
   332→        });
   333→      },
   334→
   335→      removeTagsFromLink: (id, tags) => {
   336→        set((state) => {
   337→          const link = state.links[id];
   338→          if (!link) return state;
   339→
   340→          const tagsToRemove = new Set(tags);
   341→
   342→          return {
   343→            links: {
   344→              ...state.links,
   345→              [id]: {
   346→                ...link,
   347→                tags: link.tags.filter((t) => !tagsToRemove.has(t)),
   348→                updatedAt: new Date(),
   349→              },
   350→            },
   351→          };
   352→        });
   353→      },
   354→
   355→      // ========================================================================
   356→      // Collection CRUD
   357→      // ========================================================================
   358→
   359→      addCollection: (data) => {
   360→        const id = generateCollectionId();
   361→        const now = new Date();
   362→        const maxSortOrder = Math.max(0, ...Object.values(get().collections).map((c) => c.sortOrder));
   363→
   364→        const collection: LinkCollection = {
   365→          ...data,
   366→          id,
   367→          sortOrder: maxSortOrder + 1,
   368→          createdAt: now,
   369→          updatedAt: now,
   370→        };
   371→
   372→        set((state) => ({
   373→          collections: { ...state.collections, [id]: collection },
   374→        }));
   375→
   376→        return collection;
   377→      },
   378→
   379→      updateCollection: (id, updates) => {
   380→        set((state) => {
   381→          const existing = state.collections[id];
   382→          if (!existing) return state;
   383→
   384→          return {
   385→            collections: {
   386→              ...state.collections,
   387→              [id]: {
   388→                ...existing,
   389→                ...updates,
   390→                updatedAt: new Date(),
   391→              },
   392→            },
   393→          };
   394→        });
   395→      },
   396→
   397→      deleteCollection: (id) => {
   398→        set((state) => {
   399→          const { [id]: _, ...remainingCollections } = state.collections;
   400→
   401→          // Clear active collection if it was deleted
   402→          const newActiveCollectionId =
   403→            state.activeCollectionId === id ? null : state.activeCollectionId;
   404→
   405→          return {
   406→            collections: remainingCollections,
   407→            activeCollectionId: newActiveCollectionId,
   408→          };
   409→        });
   410→      },
   411→
   412→      reorderCollections: (orderedIds) => {
   413→        set((state) => {
   414→          const updatedCollections = { ...state.collections };
   415→
   416→          orderedIds.forEach((id, index) => {
   417→            if (updatedCollections[id]) {
   418→              updatedCollections[id] = {
   419→                ...updatedCollections[id],
   420→                sortOrder: index,
   421→                updatedAt: new Date(),
   422→              };
   423→            }
   424→          });
   425→
   426→          return { collections: updatedCollections };
   427→        });
   428→      },
   429→
   430→      // ========================================================================
   431→      // Collection Operations
   432→      // ========================================================================
   433→
   434→      addLinkToCollection: (linkId, collectionId) => {
   435→        set((state) => {
   436→          const collection = state.collections[collectionId];
   437→          if (!collection || collection.linkIds.includes(linkId)) return state;
   438→
   439→          return {
   440→            collections: {
   441→              ...state.collections,
   442→              [collectionId]: {
   443→                ...collection,
   444→                linkIds: [...collection.linkIds, linkId],
   445→                updatedAt: new Date(),
   446→              },
   447→            },
   448→          };
   449→        });
   450→      },
   451→
   452→      removeLinkFromCollection: (linkId, collectionId) => {
   453→        set((state) => {
   454→          const collection = state.collections[collectionId];
   455→          if (!collection) return state;
   456→
   457→          return {
   458→            collections: {
   459→              ...state.collections,
   460→              [collectionId]: {
   461→                ...collection,
   462→                linkIds: collection.linkIds.filter((id) => id !== linkId),
   463→                updatedAt: new Date(),
   464→              },
   465→            },
   466→          };
   467→        });
   468→      },
   469→
   470→      moveLinkBetweenCollections: (linkId, fromCollectionId, toCollectionId) => {
   471→        set((state) => {
   472→          const fromCollection = state.collections[fromCollectionId];
   473→          const toCollection = state.collections[toCollectionId];
   474→
   475→          if (!fromCollection || !toCollection) return state;
   476→
   477→          return {
   478→            collections: {
   479→              ...state.collections,
   480→              [fromCollectionId]: {
   481→                ...fromCollection,
   482→                linkIds: fromCollection.linkIds.filter((id) => id !== linkId),
   483→                updatedAt: new Date(),
   484→              },
   485→              [toCollectionId]: {
   486→                ...toCollection,
   487→                linkIds: [...toCollection.linkIds, linkId],
   488→                updatedAt: new Date(),
   489→              },
   490→            },
   491→          };
   492→        });
   493→      },
   494→
   495→      reorderLinksInCollection: (collectionId, orderedLinkIds) => {
   496→        set((state) => {
   497→          const collection = state.collections[collectionId];
   498→          if (!collection) return state;
   499→
   500→          return {
   501→            collections: {
   502→              ...state.collections,
   503→              [collectionId]: {
   504→                ...collection,
   505→                linkIds: orderedLinkIds,
   506→                updatedAt: new Date(),
   507→              },
   508→            },
   509→          };
   510→        });
   511→      },
   512→
   513→      // ========================================================================
   514→      // Bulk Import
   515→      // ========================================================================
   516→
   517→      importLinks: (linksData) => {
   518→        const now = new Date();
   519→        const newLinks: Link[] = [];
   520→        const skippedDuplicates: string[] = [];
   521→
   522→        set((state) => {
   523→          const updatedLinks = { ...state.links };
   524→
   525→          // Create URL index for duplicate detection
   526→          const existingUrls = new Set(
   527→            Object.values(state.links).map((link) => link.url)
   528→          );
   529→
   530→          linksData.forEach((data) => {
   531→            // Skip duplicates (same URL)
   532→            if (existingUrls.has(data.url)) {
   533→              skippedDuplicates.push(data.url);
   534→              return;
   535→            }
   536→
   537→            const id = generateId();
   538→            const link: Link = {
   539→              ...data,
   540→              id,
   541→              visitCount: 0,
   542→              createdAt: now,
   543→              updatedAt: now,
   544→            };
   545→            updatedLinks[id] = link;
   546→            newLinks.push(link);
   547→            existingUrls.add(data.url); // Add to index to catch duplicates within import
   548→          });
   549→
   550→          return { links: updatedLinks };
   551→        });
   552→
   553→        // Log import stats for user feedback
   554→        if (skippedDuplicates.length > 0) {
   555→          console.log(
   556→            `Imported ${newLinks.length} new bookmarks, skipped ${skippedDuplicates.length} duplicates`
   557→          );
   558→        }
   559→
   560→        return newLinks;
   561→      },
   562→
   563→      // ========================================================================
   564→      // UI State
   565→      // ========================================================================
   566→
   567→      setViewMode: (mode) => set({ viewMode: mode }),
   568→      setSortField: (field) => set({ sortField: field }),
   569→      setSortDirection: (direction) => set({ sortDirection: direction }),
   570→      setSearchQuery: (query) => set({ searchQuery: query }),
   571→      setActiveCollection: (collectionId) => set({ activeCollectionId: collectionId }),
   572→
   573→      toggleLinkSelection: (id) => {
   574→        set((state) => {
   575→          const newSelection = new Set(state.selectedLinkIds);
   576→          if (newSelection.has(id)) {
   577→            newSelection.delete(id);
   578→          } else {
   579→            newSelection.add(id);
   580→          }
   581→          return { selectedLinkIds: newSelection };
   582→        });
   583→      },
   584→
   585→      selectAllLinks: (ids) => {
   586→        set({ selectedLinkIds: new Set(ids) });
   587→      },
   588→
   589→      clearSelection: () => {
   590→        set({ selectedLinkIds: new Set() });
   591→      },
   592→
   593→      // ========================================================================
   594→      // Queries
   595→      // ========================================================================
   596→
   597→      getLink: (id) => get().links[id],
   598→
   599→      getAllLinks: () => Object.values(get().links).filter((l) => !l.isArchived),
   600→
   601→      getFilteredLinks: () => {
   602→        const { activeProjectIds } = useProjectContextStore.getState();
   603→        const links = Object.values(get().links).filter((l) => !l.isArchived);
   604→
   605→        // "All" mode - no filter applied
   606→        if (activeProjectIds.length === 0) return links;
   607→
   608→        // Filter links that have ANY of the active project IDs
   609→        return links.filter((link) =>
   610→          link.projectIds.some((pid) => activeProjectIds.includes(pid))
   611→        );
   612→      },
   613→
   614→      getLinksInCollection: (collectionId) => {
   615→        const state = get();
   616→        const collection = state.collections[collectionId];
   617→        if (!collection) return [];
   618→
   619→        return collection.linkIds
   620→          .map((id) => state.links[id])
   621→          .filter((link): link is Link => link !== undefined && !link.isArchived);
   622→      },
   623→
   624→      getFavoriteLinks: () => Object.values(get().links).filter((l) => l.isFavorite && !l.isArchived),
   625→
   626→      getArchivedLinks: () => Object.values(get().links).filter((l) => l.isArchived),
   627→
   628→      searchLinks: (query) => {
   629→        const normalizedQuery = query.toLowerCase().trim();
   630→        if (!normalizedQuery) return get().getAllLinks();
   631→
   632→        return Object.values(get().links).filter((link) => {
   633→          if (link.isArchived) return false;
   634→
   635→          return (
   636→            link.title.toLowerCase().includes(normalizedQuery) ||
   637→            link.url.toLowerCase().includes(normalizedQuery) ||
   638→            link.description?.toLowerCase().includes(normalizedQuery) ||
   639→            link.category?.toLowerCase().includes(normalizedQuery) ||
   640→            link.tags.some((tag) => tag.toLowerCase().includes(normalizedQuery))
   641→          );
   642→        });
   643→      },
   644→
   645→      getAllTags: () => {
   646→        const allTags = new Set<string>();
   647→        Object.values(get().links).forEach((link) => {
   648→          link.tags.forEach((tag) => allTags.add(tag));
   649→        });
   650→        return Array.from(allTags).sort();
   651→      },
   652→
   653→      getAllCategories: () => {
   654→        const allCategories = new Set<string>();
   655→        Object.values(get().links).forEach((link) => {
   656→          if (link.category) {
   657→            allCategories.add(link.category);
   658→          }
   659→        });
   660→        return Array.from(allCategories).sort();
   661→      },
   662→    }),
   663→    {
   664→      name: 'link-library',
   665→      storage: createJSONStorage(() => createSyncedStorage()),
   666→      version: 1, // v1: Add projectIds for global project context filter
   667→      partialize: (state) => ({
   668→        // Only persist data, not UI state
   669→        links: state.links,
   670→        collections: state.collections,
   671→      }),
   672→      migrate: (persistedState: unknown, version: number) => {
   673→        let state = persistedState as any;
   674→
   675→        // Version 0 -> 1: Add projectIds field to all links
   676→        if (version < 1 && state.links) {
   677→          console.log('[LinkLibraryStore] Adding projectIds field to all links');
   678→          const updatedLinks: Record<string, Link> = {};
   679→          Object.entries(state.links).forEach(([id, link]: [string, any]) => {
   680→            updatedLinks[id] = {
   681→              ...link,
   682→              projectIds: link.projectIds ?? [],
   683→            };
   684→          });
   685→          state = {
   686→            ...state,
   687→            links: updatedLinks,
   688→          };
   689→        }
   690→
   691→        return state;
   692→      },
   693→      onRehydrateStorage: () => (state) => {
   694→        if (state?.links) {
   695→          // Convert date strings back to Date objects
   696→          Object.values(state.links).forEach((link) => {
