     1→/**
     2→ * Link Categorizer Service
     3→ *
     4→ * Uses the AI provider router to categorize links based on their URL and title.
     5→ * Provides category suggestions, tags, and confidence scores.
     6→ */
     7→
     8→import { createDefaultRouter } from './ai/providerRouter';
     9→import type { Link } from '../stores/useLinkLibraryStore';
    10→
    11→/**
    12→ * Category suggestion from AI
    13→ */
    14→export interface CategorySuggestion {
    15→  linkId: string;
    16→  category: string;
    17→  tags: string[];
    18→  confidence: number; // 0-1
    19→}
    20→
    21→/**
    22→ * Categorization result
    23→ */
    24→export interface CategorizationResult {
    25→  success: boolean;
    26→  suggestions: CategorySuggestion[];
    27→  error?: string;
    28→  providerUsed?: string;
    29→}
    30→
    31→/**
    32→ * Batch progress callback
    33→ */
    34→export type BatchProgressCallback = (
    35→  processed: number,
    36→  total: number,
    37→  currentBatch: CategorySuggestion[]
    38→) => void;
    39→
    40→/**
    41→ * Default categories for organization
    42→ */
    43→export const DEFAULT_CATEGORIES = [
    44→  'Development',
    45→  'Documentation',
    46→  'Tools',
    47→  'Design',
    48→  'News',
    49→  'Social',
    50→  'Entertainment',
    51→  'Shopping',
    52→  'Education',
    53→  'Finance',
    54→  'Health',
    55→  'Travel',
    56→  'Food',
    57→  'Sports',
    58→  'Music',
    59→  'Video',
    60→  'Gaming',
    61→  'Reference',
    62→  'Business',
    63→  'Other',
    64→] as const;
    65→
    66→/**
    67→ * System prompt for categorization
    68→ */
    69→const CATEGORIZATION_SYSTEM_PROMPT = `You are a link categorization assistant. Your task is to analyze URLs and titles to suggest appropriate categories and tags.
    70→
    71→Rules:
    72→1. Use one of these categories: ${DEFAULT_CATEGORIES.join(', ')}
    73→2. Suggest 2-5 relevant tags (lowercase, no spaces, use hyphens)
    74→3. Provide a confidence score between 0 and 1
    75→4. Be consistent in categorization
    76→5. Respond ONLY with valid JSON, no other text
    77→
    78→Example output format:
    79→[
    80→  {"id": "abc123", "category": "Development", "tags": ["javascript", "react", "frontend"], "confidence": 0.95},
    81→  {"id": "def456", "category": "Documentation", "tags": ["api", "reference"], "confidence": 0.8}
    82→]`;
    83→
    84→/**
    85→ * Build prompt for a batch of links
    86→ */
    87→function buildCategorizationPrompt(links: Link[]): string {
    88→  const linkData = links.map((link) => ({
    89→    id: link.id,
    90→    url: link.url,
    91→    title: link.title,
    92→    hostname: new URL(link.url).hostname,
    93→  }));
    94→
    95→  return `Categorize these links:
    96→
    97→${JSON.stringify(linkData, null, 2)}
    98→
    99→Respond with a JSON array of categorizations.`;
   100→}
   101→
   102→/**
   103→ * Parse AI response into category suggestions
   104→ */
   105→function parseCategorizationResponse(
   106→  content: string,
   107→  links: Link[]
   108→): CategorySuggestion[] {
   109→  try {
   110→    // Try to extract JSON from the response
   111→    let jsonContent = content.trim();
   112→
   113→    // Handle markdown code blocks
   114→    if (jsonContent.startsWith('```')) {
   115→      const jsonMatch = jsonContent.match(/```(?:json)?\s*([\s\S]*?)```/);
   116→      if (jsonMatch) {
   117→        jsonContent = jsonMatch[1].trim();
   118→      }
   119→    }
   120→
   121→    const parsed = JSON.parse(jsonContent);
   122→
   123→    if (!Array.isArray(parsed)) {
   124→      throw new Error('Response is not an array');
   125→    }
   126→
   127→    // Validate and map response
   128→    const linkIds = new Set(links.map((l) => l.id));
   129→
   130→    return parsed
   131→      .filter((item) => {
   132→        // Validate required fields exist and link ID is valid
   133→        return (
   134→          item &&
   135→          typeof item.id === 'string' &&
   136→          linkIds.has(item.id) &&
   137→          typeof item.category === 'string' &&
   138→          Array.isArray(item.tags)
   139→        );
   140→      })
   141→      .map((item) => ({
