   466→            </div>
   467→          </div>
   468→          <div className="mt-3 h-2 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-full overflow-hidden">
   469→            <div
   470→              className="h-full bg-gradient-to-r from-accent-magenta to-accent-cyan transition-all duration-300"
   471→              style={{
   472→                width: `${categorizationProgress.total > 0
   473→                  ? (categorizationProgress.processed / categorizationProgress.total) * 100
   474→                  : 0}%`,
   475→              }}
   476→            />
   477→          </div>
   478→        </div>
   479→      )}
   480→
   481→      {/* Categorization Error */}
   482→      {categorizationError && (
   483→        <div className="mb-6 p-4 rounded-button bg-accent-red/10 border border-accent-red text-accent-red">
