   489→            Dismiss
   490→          </button>
   491→        </div>
   492→      )}
   493→
   494→      {/* AI Category Suggestions */}
   495→      {pendingSuggestions.length > 0 && (
   496→        <div className="mb-6 p-4 rounded-card bg-gradient-to-r from-accent-magenta/5 to-accent-cyan/5 border border-accent-cyan/30">
   497→          <div className="flex items-center justify-between mb-4">
   498→            <div>
   499→              <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
