   507→              <button
   508→                onClick={handleAcceptAllSuggestions}
   509→                className="px-3 py-1.5 bg-accent-green hover:bg-accent-green-hover text-white rounded-button text-sm font-medium transition-colors"
   510→              >
   511→                Accept All
   512→              </button>
   513→              <button
   514→                onClick={handleDismissAllSuggestions}
   515→                className="px-3 py-1.5 border border-border-light dark:border-border-dark
   516→                           text-text-light-secondary dark:text-text-dark-secondary
   517→                           hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated
   518→                           rounded-button text-sm font-medium transition-colors"
   519→              >
   520→                Dismiss All
   521→              </button>
   522→            </div>
   523→          </div>
   524→          <div className="space-y-2 max-h-64 overflow-y-auto">
   525→            {pendingSuggestions.map((suggestion) => {
   526→              const link = links[suggestion.linkId];
   527→              if (!link) return null;
   528→              return (
   529→                <div
   530→                  key={suggestion.linkId}
   531→                  className="flex items-center gap-3 p-3 rounded-button bg-white dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark"
   532→                >
   533→                  <div className="flex-1 min-w-0">
   534→                    <p className="font-medium text-text-light-primary dark:text-text-dark-primary truncate">
   535→                      {link.title}
   536→                    </p>
   537→                    <div className="flex items-center gap-2 mt-1">
   538→                      <span className="px-2 py-0.5 text-xs rounded-full bg-accent-blue/10 text-accent-blue">
   539→                        {suggestion.category}
   540→                      </span>
   541→                      {suggestion.tags.slice(0, 3).map((tag) => (
   542→                        <span
   543→                          key={tag}
   544→                          className="px-2 py-0.5 text-xs rounded-full bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary"
   545→                        >
   546→                          {tag}
   547→                        </span>
   548→                      ))}
   549→                      <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
   550→                        {Math.round(suggestion.confidence * 100)}% confident
   551→                      </span>
   552→                    </div>
   553→                  </div>
   554→                  <button
   555→                    onClick={() => handleAcceptSuggestion(suggestion)}
   556→                    className="p-2 text-accent-green hover:bg-accent-green/10 rounded transition-colors"
