   562→                    onClick={() => handleRejectSuggestion(suggestion.linkId)}
   563→                    className="p-2 text-accent-red hover:bg-accent-red/10 rounded transition-colors"
   564→                    title="Reject"
   565→                  >
   566→                    ✕
   567→                  </button>
   568→                </div>
   569→              );
   570→            })}
   571→          </div>
   572→        </div>
   573→      )}
   574→
   575→      {/* Main Content */}
   576→      {displayedLinks.length === 0 ? (
   577→        /* Empty State / Drop Zone */
   578→        <div
   579→          onDrop={handleDrop}
   580→          onDragOver={handleDragOver}
   581→          className="flex-1 flex flex-col items-center justify-center p-8
   582→                     border-2 border-dashed border-border-light dark:border-border-dark rounded-card
   583→                     bg-surface-light dark:bg-surface-dark-elevated"
   584→        >
   585→          {isImporting ? (
   586→            <div className="flex flex-col items-center gap-4">
   587→              <div className="w-12 h-12 border-4 border-accent-blue border-t-transparent rounded-full animate-spin" />
   588→              <p className="text-text-light-secondary dark:text-text-dark-secondary">
   589→                Importing bookmarks...
   590→              </p>
   591→            </div>
   592→          ) : (
   593→            <>
   594→              <span className="text-6xl mb-4">🔗</span>
   595→              <h3 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
   596→                {searchQuery ? 'No links found' : 'No links yet'}
   597→              </h3>
   598→              <p className="text-text-light-secondary dark:text-text-dark-secondary text-center max-w-md mb-6">
   599→                {searchQuery
   600→                  ? `No links match "${searchQuery}"`
   601→                  : 'Import your browser bookmarks or add links manually to get started.'}
   602→              </p>
   603→              {!searchQuery && (
   604→                <div className="flex flex-col items-center gap-2">
   605→                  <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
