   607→                  </p>
   608→                  <label className="px-6 py-3 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button
   609→                                   text-base font-medium cursor-pointer transition-colors">
   610→                    Choose File
   611→                    <input
   612→                      type="file"
   613→                      accept=".html,.htm"
   614→                      onChange={handleFileInput}
   615→                      className="hidden"
   616→                    />
   617→                  </label>
   618→                </div>
   619→              )}
   620→            </>
   621→          )}
   622→        </div>
   623→      ) : (
   624→        /* Links Grid/List */
   625→        <div className="flex-1 overflow-y-auto">
   626→          {/* Select All Checkbox */}
   627→          <div className="flex items-center gap-2 mb-4">
   628→            <input
   629→              type="checkbox"
   630→              checked={selectedLinkIds.size === displayedLinks.length && displayedLinks.length > 0}
   631→              onChange={handleSelectAll}
   632→              className="w-4 h-4 rounded border-border-light dark:border-border-dark"
