   634→            <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
   635→              Select All
   636→            </span>
   637→          </div>
   638→
   639→          {viewMode === 'grid' ? (
   640→            /* Grid View */
   641→            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
