   645→                  link={link}
   646→                  isSelected={selectedLinkIds.has(link.id)}
   647→                  onToggleSelect={() => toggleLinkSelection(link.id)}
   648→                  onToggleFavorite={() => toggleFavorite(link.id)}
   649→                  onToggleArchive={() => toggleArchived(link.id)}
   650→                />
   651→              ))}
   652→            </div>
   653→          ) : (
   654→            /* List View */
   655→            <div className="space-y-2">
   656→              {displayedLinks.map((link) => (
   657→                <LinkListItem
