   659→                  link={link}
   660→                  isSelected={selectedLinkIds.has(link.id)}
   661→                  onToggleSelect={() => toggleLinkSelection(link.id)}
   662→                  onToggleFavorite={() => toggleFavorite(link.id)}
   663→                  onToggleArchive={() => toggleArchived(link.id)}
   664→                />
   665→              ))}
   666→            </div>
   667→          )}
   668→        </div>
   669→      )}
   670→        </div>
   671→      </div>
   672→    </PageContent>
   673→  );
   674→};
   675→
   676→// ============================================================================
   677→// Link Card Component (Grid View)
   678→// ============================================================================
   679→
   680→interface LinkCardProps {
   681→  link: Link;
   682→  isSelected: boolean;
   683→  onToggleSelect: () => void;
   684→  onToggleFavorite: () => void;
   685→  onToggleArchive: () => void;
   686→}
   687→
   688→const LinkCard: React.FC<LinkCardProps> = ({
   689→  link,
   690→  isSelected,
   691→  onToggleSelect,
   692→  onToggleFavorite,
   693→  onToggleArchive,
   694→}) => {
   695→  const faviconUrl = `https://www.google.com/s2/favicons?domain=${new URL(link.url).hostname}&sz=32`;
   696→
   697→  return (
   698→    <div
   699→      className={`
   700→        p-4 rounded-card bg-surface-light dark:bg-surface-dark-elevated
   701→        border transition-all duration-200
   702→        ${isSelected
   703→          ? 'border-accent-blue ring-2 ring-accent-blue/20'
   704→          : 'border-border-light dark:border-border-dark hover:border-accent-blue/50'
   705→        }
   706→      `}
   707→    >
   708→      {/* Header */}
   709→      <div className="flex items-start gap-3 mb-3">
   710→        <input
   711→          type="checkbox"
   712→          checked={isSelected}
   713→          onChange={onToggleSelect}
   714→          className="mt-1 w-4 h-4 rounded border-border-light dark:border-border-dark"
   715→        />
   716→        <img
   717→          src={faviconUrl}
   718→          alt=""
   719→          className="w-6 h-6 rounded flex-shrink-0"
   720→          onError={(e) => {
   721→            (e.target as HTMLImageElement).src = 'data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="%236b7280"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-1 17.93c-3.95-.49-7-3.85-7-7.93 0-.62.08-1.21.21-1.79L9 15v1c0 1.1.9 2 2 2v1.93zm6.9-2.54c-.26-.81-1-1.39-1.9-1.39h-1v-3c0-.55-.45-1-1-1H8v-2h2c.55 0 1-.45 1-1V7h2c1.1 0 2-.9 2-2v-.41c2.93 1.19 5 4.06 5 7.41 0 2.08-.8 3.97-2.1 5.39z"/></svg>';
   722→          }}
   723→        />
   724→        <div className="flex-1 min-w-0">
   725→          <a
   726→            href={link.url}
   727→            target="_blank"
   728→            rel="noopener noreferrer"
   729→            className="block font-medium text-text-light-primary dark:text-text-dark-primary
   730→                       hover:text-accent-blue truncate"
   731→          >
   732→            {link.title}
   733→          </a>
   734→          <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary truncate">
   735→            {new URL(link.url).hostname}
   736→          </p>
   737→        </div>
   738→      </div>
   739→
   740→      {/* Category & Tags */}
   741→      {(link.category || link.tags.length > 0) && (
   742→        <div className="flex flex-wrap gap-1 mb-3">
   743→          {link.category && (
   744→            <span className="px-2 py-0.5 text-xs rounded-full bg-accent-blue/10 text-accent-blue">
   745→              {link.category}
   746→            </span>
   747→          )}
   748→          {link.tags.slice(0, 2).map((tag) => (
   749→            <span
   750→              key={tag}
   751→              className="px-2 py-0.5 text-xs rounded-full bg-surface-light-elevated dark:bg-surface-dark-elevated
   752→                         text-text-light-secondary dark:text-text-dark-secondary"
   753→            >
   754→              {tag}
   755→            </span>
   756→          ))}
   757→          {link.tags.length > 2 && (
   758→            <span className="px-2 py-0.5 text-xs text-text-light-secondary dark:text-text-dark-secondary">
   759→              +{link.tags.length - 2}
   760→            </span>
   761→          )}
   762→        </div>
   763→      )}
   764→
   765→      {/* Actions */}
   766→      <div className="flex items-center gap-2 pt-2 border-t border-border-light dark:border-border-dark">
   767→        <button
   768→          onClick={onToggleFavorite}
   769→          className={`p-1.5 rounded transition-colors ${link.isFavorite
   770→              ? 'text-accent-yellow'
   771→              : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-accent-yellow'
   772→            }`}
   773→          title={link.isFavorite ? 'Remove from favorites' : 'Add to favorites'}
   774→        >
   775→          {link.isFavorite ? '★' : '☆'}
   776→        </button>
   777→        <button
   778→          onClick={onToggleArchive}
   779→          className="p-1.5 rounded text-text-light-secondary dark:text-text-dark-secondary
   780→                     hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
   781→          title={link.isArchived ? 'Unarchive' : 'Archive'}
   782→        >
   783→          📥
   784→        </button>
   785→        <div className="flex-1" />
   786→        <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
   787→          {link.visitCount > 0 && `${link.visitCount} visits`}
   788→        </span>
   789→      </div>
   790→    </div>
   791→  );
   792→};
   793→
   794→// ============================================================================
   795→// Link List Item Component (List View)
   796→// ============================================================================
   797→
   798→const LinkListItem: React.FC<LinkCardProps> = ({
   799→  link,
