   342→              <span className="text-xs">✏️</span>
   343→            </button>
   344→          )}
   345→          {onDelete && (
   346→            <button
   347→              onClick={(e) => {
   348→                e.stopPropagation();
   349→                onDelete();
   350→              }}
   351→              className="p-1 rounded hover:bg-status-error/20 text-status-error transition-colors"
   352→              title="Delete"
   353→            >
   354→              <span className="text-xs">🗑️</span>
   355→            </button>
   356→          )}
   357→        </div>
   358→      )}
   359→    </button>
   360→  );
   361→};
   362→
   363→export default CollectionSidebar;
